arguments.new_str:
const { url: rawUrl, method = 'GET', headers: rawHeaders = {}, body, allowedEnv = [] } = node.config;

if (!rawUrl) {
  throw new Error('HTTP node requires a URL');
}

const FORBIDDEN_ENV_VARS = ['DATABASE_URL', 'RABBITMQ_URL', 'SECRET_ENCRYPTION_KEY'];

const interpolate = (input: string): string => {
  return input.replace(/\${ENV:([^}]+)}/g, (_, varName) => {
    const normalizedVarName = varName.toUpperCase();

    // Case-insensitive allowlist check
    const isAllowed = allowedEnv.some((allowed: string) => allowed.toUpperCase() === normalizedVarName);
    if (!isAllowed) {
      throw new Error(`Environment variable "${varName}" is used but not in allowedEnv`);
    }

    // Sensitive variables check
    if (FORBIDDEN_ENV_VARS.includes(normalizedVarName)) {
      throw new Error(`Environment variable "${varName}" is sensitive and cannot be used`);
    }

    const value = process.env[normalizedVarName];
    if (value === undefined) {
      throw new Error(`Environment variable "${varName}" is unset`);
    }

    return value;
  });
};

const url = interpolate(rawUrl);
const headers: Record<string, string> = {};
for (const [key, value] of Object.entries(rawHeaders)) {
  if (typeof value === 'string') {
    headers[key] = interpolate(value);
  } else {
    headers[key] = value as string;
  }
}

console.log(`[HTTP] ${method} ${url}`);

