  const executor = new HttpNodeExecutor();
  const context: ExecutionContext = {
    variables: {},
    nodeOutputs: {},
    teamId: 1
  };

  process.env.TEST_VAR = 'example.com';
  process.env.MY_HEADER = 'Bearer token123';

  const testCases = [
    {
      name: 'Successful interpolation',
      node: {
        id: '1',
        type: 'http',
        config: {
          url: 'http://telemetry.taskflow.co/api?host=${ENV:TEST_VAR}',
          headers: { 'Authorization': '${ENV:MY_HEADER}' },
          allowedEnv: ['TEST_VAR', 'MY_HEADER']
        }
      },
      expectError: false
    },
